function (train_data, test_data, target_variable, mstop = c(5,      10, 20, 50, 100), nu = c(0.01, 0.1, 0.3, 0.5), risk = c("oobag",      "inbag", "none"), stopintern = c(FALSE, TRUE), center = c(FALSE,      TRUE), trace = c(FALSE, TRUE), seed = 123)  {     if (!requireNamespace("mboost", quietly = TRUE)) {         install.packages("mboost")     }     library(mboost)     train_data <- as.data.frame(train_data)     test_data <- as.data.frame(test_data)     X_train <- train_data[, !(names(train_data) %in% target_variable),          drop = FALSE]     y_train <- train_data[[target_variable]]     X_test <- test_data[, colnames(X_train), drop = FALSE]     X_train <- as.matrix(X_train)     X_test <- as.matrix(X_test)     y_train <- as.numeric(y_train)     formula <- as.formula(paste(target_variable, "~ ."))     best_rmse <- Inf     best_correlation <- -Inf     best_params <- NULL     best_predictions <- NULL     best_model <- NULL     for (mstop in mstop) {         for (nu in nu) {             for (risk in risk) {                 for (stopintern in stopintern) {                   for (center in center) {                     for (trace in trace) {                       set.seed(seed)                       mboost_fit <- glmboost(formula, data = train_data,                          family = Gaussian(), control = boost_control(mstop = mstop,                            nu = nu, stopintern = stopintern, center = center,                            trace = trace))                       predictions <- predict(mboost_fit, newdata = test_data)                       predictions_vec <- as.numeric(predictions)                       actual_values <- as.numeric(test_data[[target_variable]])                       rmse <- sqrt(mean((actual_values - predictions_vec)^2))                       correlation <- cor(predictions_vec, actual_values,                          use = "complete.obs")                       if (rmse < best_rmse | (rmse == best_rmse &                          correlation > best_correlation)) {                         best_rmse <- rmse                         best_correlation <- correlation                         best_params <- list(mstop = mstop, nu = nu,                            stopintern = stopintern, center = center,                            trace = trace)                         best_predictions <- predictions_vec                         best_model <- mboost_fit                       }                     }                   }                 }             }         }     }     return(list(predictions = best_predictions, RMSE = best_rmse,          correlation = best_correlation, best_params = best_params,          model = best_model)) }